using System.Reflection;
var asm = typeof(Microsoft.Agents.AI.ChatClientAgent).Assembly;

// Check return types
var agentType = typeof(Microsoft.Agents.AI.ChatClientAgent);
foreach (var m in agentType.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly).Where(m => m.Name == "RunAsync" && !m.IsGenericMethod).Take(1))
{
    Console.WriteLine($"RunAsync returns: {m.ReturnType}");
    if (m.ReturnType.IsGenericType)
    {
        var innerType = m.ReturnType.GetGenericArguments()[0];
        Console.WriteLine($"  Inner type: {innerType.FullName} : {innerType.BaseType?.Name}");
        foreach (var p in innerType.GetProperties(BindingFlags.Public | BindingFlags.Instance))
            Console.WriteLine($"  P: {p.PropertyType} {p.Name}");
    }
}

// Check AgentRunOptions as base
var runOptType = typeof(Microsoft.Agents.AI.ChatClientAgentRunOptions).BaseType!;
Console.WriteLine($"\n--- {runOptType.FullName}");
foreach (var p in runOptType.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
    Console.WriteLine($"  P: {p.PropertyType.Name} {p.Name}");

// Check AIAgent base
var aiAgentType = agentType.BaseType!;
Console.WriteLine($"\n--- {aiAgentType.FullName}");
foreach (var p in aiAgentType.GetProperties(BindingFlags.Public | BindingFlags.Instance))
