using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

// --- DI & chat client setup ---------------------------------------------------

var services = new ServiceCollection();
services.AddLogging(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning));
services.AddChatClient(b => b.UseOpenAIChatClient("gpt-4o-mini-2024-07-18"))
    .Use(new OpenAI.OpenAIClient(apiKey));

var sp = services.BuildServiceProvider();
var chatClient = sp.GetRequiredService<IChatClient>();

// --- Tools --------------------------------------------------------------------

var notebook = new Notebook();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(
        ([Description("The search query")] string query) =>
        {
            return WebSearchAsync(query);
        },
        "web_search",
        "Searches the web for a query and returns a summary of the top results. " +
        "Use this to gather information about a topic."),

    AIFunctionFactory.Create(
        ([Description("Title for the note")] string title,
         [Description("Content to save")] string content) =>
        {
            notebook.Add(title, content);
            return $"Note saved: \"{title}\"";
        },
        "save_note",
        "Saves a research note with a title and content. " +
        "Use this to record key findings as you research."),

    AIFunctionFactory.Create(
        () => notebook.GetAll(),
        "get_notes",
        "Returns all saved research notes. " +
        "Use this to review what you've already recorded before writing a summary."),
};

// --- Agent creation -----------------------------------------------------------

var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. When the user provides a topic:
        1. Search the web multiple times to gather diverse information about the topic.
        2. Save important findings as notes using the save_note tool.
        3. After gathering enough information, review your notes with get_notes.
        4. Produce a well-structured summary with key findings and sources.
        Be thorough but concise. Aim for 3-5 searches before summarizing.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics using web search and note-taking.",
    tools: tools);

// --- Run ----------------------------------------------------------------------

Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent (GPT-4o)     ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

string topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptUser("Enter a research topic: ");

Console.WriteLine($"\n🔍 Researching: {topic}\n");

var session = await agent.CreateSessionAsync();
var response = await agent.RunAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session);

Console.WriteLine("─── Research Summary ────────────────────");
Console.WriteLine(response.Text);
Console.WriteLine("─────────────────────────────────────────");

if (notebook.Count > 0)
{
    Console.WriteLine($"\n📝 {notebook.Count} note(s) saved during research.");
}

// --- Helpers ------------------------------------------------------------------

static string PromptUser(string prompt)
{
    Console.Write(prompt);
    var input = Console.ReadLine()?.Trim();
    return string.IsNullOrEmpty(input)
        ? throw new InvalidOperationException("A research topic is required.")
        : input;
}

static async Task<string> WebSearchAsync(string query)
{
    using var http = new HttpClient();
    http.DefaultRequestHeaders.UserAgent.ParseAdd(
        "ResearchAgent/1.0 (compatible; +https://example.com/bot)");

    var encoded = WebUtility.UrlEncode(query);
    var url = $"https://html.duckduckgo.com/html/?q={encoded}";

    try
    {
        var html = await http.GetStringAsync(url);
        return ParseSearchResults(html);
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}";
    }
}

static string ParseSearchResults(string html)
{
    var sb = new StringBuilder();
    var resultPattern = new Regex(
        @"<a[^>]+class=""result__a""[^>]*>(?<title>.*?)</a>.*?" +
        @"<a[^>]+class=""result__snippet""[^>]*>(?<snippet>.*?)</a>",
        RegexOptions.Singleline | RegexOptions.IgnoreCase);

    var matches = resultPattern.Matches(html);
    var count = 0;

    foreach (Match m in matches)
    {
        if (count >= 5) break;
        var title = StripHtml(m.Groups["title"].Value).Trim();
        var snippet = StripHtml(m.Groups["snippet"].Value).Trim();
        if (string.IsNullOrWhiteSpace(title)) continue;

        sb.AppendLine($"[{++count}] {title}");
        if (!string.IsNullOrWhiteSpace(snippet))
            sb.AppendLine($"    {snippet}");
        sb.AppendLine();
    }

    return count > 0
        ? sb.ToString()
        : "No results found. Try a different query.";
}

static string StripHtml(string html)
    => Regex.Replace(html, "<.*?>", string.Empty)
           .Replace("&amp;", "&")
           .Replace("&lt;", "<")
           .Replace("&gt;", ">")
           .Replace("&quot;", "\"")
           .Replace("&#x27;", "'");

// --- Notebook type ------------------------------------------------------------

sealed class Notebook
{
    private readonly List<(string Title, string Content)> _notes = [];

    public int Count => _notes.Count;

    public void Add(string title, string content) => _notes.Add((title, content));

    public string GetAll()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"--- Note {i + 1}: {_notes[i].Title} ---");
            sb.AppendLine(_notes[i].Content);
            sb.AppendLine();
        }
        return sb.ToString();
    }
}

