15.     .GetChatClient(modelId)
16.     .AsIChatClient();
17. 
18. // --- Tools --------------------------------------------------------------------
19. 
20. var notebook = new Notebook();
21. 
22. var tools = new List<AITool>
23. {
24.     AIFunctionFactory.Create(
25.         ([Description("The search query")] string query) =>
26.         {
27.             return WebSearchAsync(query);
28.         },
