42.         "Use this to record key findings as you research."),
43. 
44.     AIFunctionFactory.Create(
45.         () => notebook.GetAll(),
46.         "get_notes",
47.         "Returns all saved research notes. " +
48.         "Use this to review what you've already recorded before writing a summary."),
49. };
50. 
51. // --- Agent creation -----------------------------------------------------------
52. 
53. var agent = new ChatClientAgent(
54.     chatClient,
55.     instructions: """
56.         You are a research agent. When the user provides a topic:
57.         1. Search the web multiple times to gather diverse information about the topic.
58.         2. Save important findings as notes using the save_note tool.
59.         3. After gathering enough information, review your notes with get_notes.
60.         4. Produce a well-structured summary with key findings and sources.
61.         Be thorough but concise. Aim for 3-5 searches before summarizing.
62.         """,
63.     name: "ResearchAgent",
64.     description: "An agent that researches topics using web search and note-taking.",
65.     tools: tools);
66. 
67. // --- Run ----------------------------------------------------------------------
68. 
69. Console.WriteLine("╔══════════════════════════════════════╗");
70. Console.WriteLine("║       AI Research Agent (GPT-4o)     ║");
71. Console.WriteLine("╚══════════════════════════════════════╝");
72. Console.WriteLine();
73. 
74. string topic = args.Length > 0
75.     ? string.Join(' ', args)
76.     : PromptUser("Enter a research topic: ");
77. 
78. Console.WriteLine($"\n🔍 Researching: {topic}\n");
79. 
80. var session = await agent.CreateSessionAsync();
81. var response = await agent.RunAsync(
82.     $"Research the following topic and provide a comprehensive summary: {topic}",
83.     session);
84. 
85. Console.WriteLine("─── Research Summary ────────────────────");
86. Console.WriteLine(response.Text);
87. Console.WriteLine("─────────────────────────────────────────");
88. 
89. if (notebook.Count > 0)
90. {
91.     Console.WriteLine($"\n📝 {notebook.Count} note(s) saved during research.");
92. }
93. 
94. // --- Helpers ------------------------------------------------------------------
95. 
96. static string PromptUser(string prompt)
97. {
98.     Console.Write(prompt);
99.     var input = Console.ReadLine()?.Trim();
100.     return string.IsNullOrEmpty(input)
101.         ? throw new InvalidOperationException("A research topic is required.")
102.         : input;
103. }
104. 
105. static async Task<string> WebSearchAsync(string query)
106. {
107.     using var http = new HttpClient();
108.     http.DefaultRequestHeaders.UserAgent.ParseAdd(
109.         "ResearchAgent/1.0 (compatible; +https://example.com/bot)");
110. 
111.     var encoded = WebUtility.UrlEncode(query);
112.     var url = $"https://html.duckduckgo.com/html/?q={encoded}";
113. 
114.     try
115.     {
116.         var html = await http.GetStringAsync(url);
117.         return ParseSearchResults(html);
118.     }
119.     catch (Exception ex)
120.     {
121.         return $"Search failed: {ex.Message}";
122.     }
123. }
124. 
125. static string ParseSearchResults(string html)
126. {
127.     var sb = new StringBuilder();
128.     var resultPattern = new Regex(
129.         @"<a[^>]+class=""result__a""[^>]*>(?<title>.*?)</a>.*?" +
130.         @"<a[^>]+class=""result__snippet""[^>]*>(?<snippet>.*?)</a>",
131.         RegexOptions.Singleline | RegexOptions.IgnoreCase);
132. 
133.     var matches = resultPattern.Matches(html);
134.     var count = 0;
135. 
136.     foreach (Match m in matches)
137.     {
138.         if (count >= 5) break;
139.         var title = StripHtml(m.Groups["title"].Value).Trim();
140.         var snippet = StripHtml(m.Groups["snippet"].Value).Trim();
141.         if (string.IsNullOrWhiteSpace(title)) continue;
142. 
143.         sb.AppendLine($"[{++count}] {title}");
144.         if (!string.IsNullOrWhiteSpace(snippet))
145.             sb.AppendLine($"    {snippet}");
146.         sb.AppendLine();
147.     }
148. 
149.     return count > 0
150.         ? sb.ToString()
151.         : "No results found. Try a different query.";
152. }
153. 
154. static string StripHtml(string html)
155.     => Regex.Replace(html, "<.*?>", string.Empty)
156.            .Replace("&amp;", "&")
157.            .Replace("&lt;", "<")
158.            .Replace("&gt;", ">")
159.            .Replace("&quot;", "\"")
160.            .Replace("&#x27;", "'");
161. 
162. // --- Notebook type ------------------------------------------------------------
163. 
164. sealed class Notebook
165. {
166.     private readonly List<(string Title, string Content)> _notes = [];
167. 
168.     public int Count => _notes.Count;
169. 
170.     public void Add(string title, string content) => _notes.Add((title, content));
171. 
172.     public string GetAll()
173.     {
174.         if (_notes.Count == 0)
175.             return "No notes saved yet.";
176. 
177.         var sb = new StringBuilder();
178.         for (var i = 0; i < _notes.Count; i++)
179.         {
180.             sb.AppendLine($"--- Note {i + 1}: {_notes[i].Title} ---");
181.             sb.AppendLine(_notes[i].Content);
182.             sb.AppendLine();
183.         }
184.         return sb.ToString();
185.     }
186. }
